let email = "";
let subject = "";
let body = "";

// Loop through all items
for (const item of items) {
  // Get email & subject if present
  if (item.json.email) email = item.json.email;
  if (item.json.subject) subject = item.json.subject;

  // Get body from Gemini output
  if (item.json.output) {
    body = item.json.output
      .replace(/```html\s*|```/g, "")  // remove code block markers
      .trim();
  }
}

// Return single item for Gmail
return [
  {
    json: {
      email,
      subject,
      body
    }
  }
];

const email = $json.email || "";
const subject = $json.subject || "";
const bodyHtml = $json.body || "";

// Build a prompt for the AI agent
const prompt = `
You are a helpful assistant. You need to take the following HTML email body and reformat it professionally for Gmail. 

Requirements:
1. Preserve all the text content.
2. Apply a clean, professional font (e.g., Arial, sans-serif) and proper line spacing.
3. Bold important phrases and headings naturally where appropriate.
4. Remove unnecessary things like empty spaces or irrelevant tags.
5. Keep it fully HTML so it can be used directly in an n8n Gmail node.
6. Do not add or change the email recipient or subject, just format the body content.

Original HTML Body:
${bodyHtml}

Return only the **formatted HTML** in your output.
`.trim();

return [
  {
    json: {
      email,
      subject,
      prompt
    }
  }
];

// Input text from transcription
const text = $json.content?.parts?.[0]?.text || "";

// Generic prompt to extract recipient, file name, and document name
const prompt = `
You are an assistant that extracts structured data.

From the given text, do the following:
1. Extract the email address (normalize and validate if present).
2. Detect if the user mentioned sending or attaching any file/document.
3. Extract the file name exactly as mentioned (if any, e.g., "report.pdf", "cv.docx", "sales_data").
4. Extract the document name as a clean, human-readable title (remove extensions, underscores, etc.; e.g., "Report", "CV", "Sales Data").

Return ONLY valid JSON:
{
  "recipient": "<email or null>",
  "fileName": "<file name or null>",
  "documentName": "<document name or null>"
}

Text: """${text}"""
`;

return [{ json: { prompt } }];

const message = $json.output || "";

// Default subject
let subject = "Message for You";

// Step 1: Keyword-based detection
if (/cover letter/i.test(message)) {
  subject = "Cover Letter";
} else if (/weather/i.test(message)) {
  subject = "Weather Update";
} else if (/reminder/i.test(message)) {
  subject = "Reminder";
} else if (/report/i.test(message)) {
  subject = "Report";
} else if (/update/i.test(message)) {
  subject = "Update";
} else if (/hello|hi|greeting|good morning|good evening/i.test(message)) {
  subject = "Greeting";
} else if (/thank/i.test(message)) {
  subject = "Thank You Note";
} else {
  // Step 2: Fallback → extract key words
  const words = message
    .replace(/[^\w\s]/g, "") // remove punctuation
    .split(/\s+/)
    .filter(w => w.length > 3); // ignore very short words

  // Take 3 words from start and 3 from end
  const start = words.slice(0, 3).join(" ");
  const end = words.slice(-3).join(" ");

  subject = `${start} ... ${end}`;
}

// Step 3: Extract email from the message (if any)
let email = null;
const emailMatch = message.match(/[a-zA-Z0-9._%+-]+@[a-zA-Z0-9.-]+\.[a-z]{2,}/);
if (emailMatch) {
  email = emailMatch[0];
}

// Return subject + original message + extracted email
return [
  {
    json: {
      subject,
      message,
      email
    }
  }
];

const email = $json.email || "";
const subject = $json.subject || "Message for You";
const message = $json.message || "";
const recipient = $json.recipient || "Friend"; // fallback if not provided

// Professional HTML body without placeholder name
const formattedBody = `
<html>
  <body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333;">
    <p>Dear ${recipient},</p>
    <p>${message}</p>
    <p style="margin-top: 20px;">Best regards,</p>
  </body>
</html>
`.trim();

return [
  {
    json: {
      email,
      subject,
      body: formattedBody
    }
  }
];

const text = $json.text || "";
const email = $json.email || "";

// Build a generic prompt for Gemini
const prompt = `
You are a helpful assistant.

User said: "${text}"
Recipient email (must be used exactly as given, no changes allowed): "${email}"

Your job:
1. Understand what the user is asking.
2. If it's a generic request like "send a message", create a short, natural, friendly greeting message.
3. If it's a specific request (e.g., weather report, cover letter, reminder, update), generate a clear and human-like message body that matches exactly what was asked.
4. Do not include the recipient name in the message body.
5. Return ONLY valid JSON in the following format (email must be exactly the same as provided, without edits):

{
  "email": "${email}",
  "message": "<generated message text>"
}
`.trim();

return [
  {
    json: {
      email,
      prompt
    }
  }
];

let recipient = null;
let transcription = null;
let fileName = null;

// Step 1: Get recipient (email) and fileName from Gemini/AI output
for (const item of items) {
  if (item.json.output && typeof item.json.output === "string") {
    try {
      const parsed = JSON.parse(item.json.output.replace(/```json|```/g, "").trim());
      if (parsed.recipient) {
        recipient = parsed.recipient.trim();
      }
      if (parsed.fileName) {
        fileName = parsed.fileName.trim();
      }
    } catch (e) {
      // ignore parsing errors
    }
  }
}

// Step 2: Get transcription text
for (const item of items) {
  if (item.json.content && item.json.content.parts) {
    transcription = item.json.content.parts[0].text.trim();
  }
}

// Step 3: Directly use recipient as email
let email = recipient || null;

// Step 4: Return combined output
return [
  {
    json: {
      email,
      fileName,
      text: transcription
    }
  }
];
